import json
from typing import Any, Dict, Optional, Tuple

import jwt
from jwt import InvalidTokenError


def debug_jwt(
    token: str,
    secret: Optional[str] = None,
    algorithms: Optional[list] = None,
    audience: Optional[str] = None,
    issuer: Optional[str] = None,
    verify: bool = True,
) -> Tuple[Dict[str, Any], Dict[str, Any]]:
    """
    Decode and (optionally) verify a JWT.

    Args:
        token: The JWT string.
        secret: Shared secret or public key for verification.
        algorithms: List of accepted algorithms, e.g. ["HS256", "RS256"].
        audience: Expected audience claim.
        issuer: Expected issuer claim.
        verify: If False, skip signature verification.

    Returns:
        Tuple of (header, payload) dictionaries.

    Raises:
        InvalidTokenError: If verification fails.
    """
    algorithms = algorithms or ["HS256", "RS256"]

    # First decode header without verification for inspection
    header = jwt.get_unverified_header(token)

    # Set verification options
    options = {"verify_signature": verify, "verify_aud": audience is not None, "verify_iss": issuer is not None}

    try:
        payload = jwt.decode(
            token,
            key=secret,
            algorithms=algorithms,
            audience=audience,
            issuer=issuer,
            options=options,
        )
    except InvalidTokenError as exc:
        raise InvalidTokenError(f"JWT verification failed: {exc}") from exc

    # Pretty–print for quick inspection
    print("Header:")
    print(json.dumps(header, indent=2))
    print("\nPayload:")
    print(json.dumps(payload, indent=2))

    return header, payload


